    {
      "id": "assets_psirts",
      "from_table": "assets",
      "from_column": "serial_number",
      "to_table": "psirts",
      "to_column": "serial_number",
      "cardinality": "1:*",
      "description": "An asset may have many PSIRT vulnerability records",
      "from_table_ref": "postgresql.public.cvi_assets_view_1__3__9",
      "to_table_ref": "postgresql.public.cvi_psirts_view_1__3__11"
    },
    {
      "id": "psirts_bulletins",
      "from_table": "psirts",
      "from_column": "psirt_id",
      "to_table": "bulletins",
      "to_column": "psirt_id",
      "cardinality": "*:1",
      "description": "Many PSIRT records link to one PSIRT bulletin definition",
      "from_table_ref": "postgresql.public.cvi_psirts_view_1__3__11",
      "to_table_ref": "postgresql.public.pas_psirt_bulletins_view_1__3__1"
    }
  ],
  "notes": [
    "Primary table is 'assets' (cvi_assets_view). JOIN psirts on serial_number for vulnerability data.",
    "JOIN bulletins on psirt_id when filtering or enriching with PSIRT bulletin-level data.",
    "Use psirts.vulnerability_status (VUL/POTVUL) to filter vulnerable assets.",
    "Use assets advisory count fields (advisory_count, affected_security_advisories_count, etc.) ONLY for per-device filtering (e.g. WHERE critical_security_advisories_count > 0). NEVER use SUM() on these count fields to get total distinct advisories — that double-counts advisories shared across devices. To count total distinct advisories, JOIN to the psirts table and use COUNT_DISTINCT on psirts.psirt_id.",
    "The severity column on bulletins is 'severity_level_name' (e.g. 'Critical', 'High', 'Medium'). There is NO column called 'severity' on bulletins — always use bulletins.severity_level_name.",
    "To count advisories broken down by severity: use COUNT_DISTINCT on psirts.psirt_id with GROUP BY bulletins.severity_level_name and filter WHERE bulletins.severity_level_name IN ('Critical', 'High'). Do NOT use two identical COUNT(DISTINCT psirt_id) columns without a GROUP BY or CASE WHEN — that returns the same number for both.",
    "Prefer platform_account_id and/or serial_number filters for tenant-safe lookups."
  ],
  "example_filters": [
    {
      "column": "psirts.vulnerability_status",
      "operator": "=",
      "value": "VUL"
    },
    {
      "column": "assets.affected_security_advisories_count",
      "operator": ">",
      "value": 0
    }
  ]
}

